import { BLANK_CLUSTER, PRODUCT_NAME } from './constants';

export function init($plugin, store) {
  const { product, basicType } = $plugin.DSL(store, PRODUCT_NAME);

  product({
    icon: 'pod',
    inStore: 'cluster',
    removable: false,
    weight: 100,
    to: {
      name: `c-cluster-${ PRODUCT_NAME }-overview`,
      params: {
        cluster: BLANK_CLUSTER,
      },
    },
  });

  basicType([
    'overview',
    'history',
  ]);
}

export default init;
